const raw = items[0]?.json?.output;

const category = $node["Pre LLM"].json.category;

if (!raw || typeof raw !== "string") {
  throw new Error("LLM output is missing or not a string");
}

// Remove markdown code fences if present
const cleaned = raw
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error(
    "Failed to parse LLM output as JSON.\nRaw output:\n" + cleaned
  );
}

// Return structured JSON with category included
return [
  {
    json: {
      category_name: category,
      ...parsed
    }
  }
];

// Input: $json is each item returned by Fetch Spec / normalizer
// Output: { mcat_id, finalized_spec_url }

const out = [];
const item = $json; // current batch item

// helper to safely read nested path
function get(obj, path, def = undefined) {
  return path.split('.').reduce((a, b) => (a && a[b] !== undefined) ? a[b] : def, obj);
}

const mcat_id = item.mcat_id || get(item, 'mcatId') || null;

// Try the canonical path: finalized_specs.file_info.url
let url = get(item, 'finalized_specs.file_info.url');

// fallback: sometimes file_info might be array, or finalized_specs may be null
if (!url) {
  // case: finalized_specs.file_info could be an array
  const fileInfo = get(item, 'finalized_specs.file_info');
  if (Array.isArray(fileInfo) && fileInfo.length > 0) {
    url = fileInfo[0].url || fileInfo[0].download_url || null;
  }
}

// ultimate fallback: search object for any https://storage.googleapis.com/... occurrence
if (!url) {
  const jsonStr = JSON.stringify(item);
  const m = jsonStr.match(/https:\/\/storage\.googleapis\.com\/[^\s"']+/);
  if (m) url = m[0];
}

return [{ json: { mcat_id, finalized_spec_url: url || null } }];
