const buyerSpecs = items[0].json.buyer_specs;

// Keep specs where product count > 2 and sort descending
const validSpecs = buyerSpecs
  .filter(s => Number(s.total_product_count) > 2)
  .sort((a, b) => Number(b.total_product_count) - Number(a.total_product_count));

return [{
  json: {
    buyer_specs: validSpecs
  }
}];

for (const item of $input.all()) {
  const data = item.json;

  let targetFile = null;

  // 1️⃣ Try Primary File (step_11_normalizer_output)
  if (
    data.steps &&
    data.steps.step_11_normalizer_output &&
    data.steps.step_11_normalizer_output.root_files
  ) {
    targetFile = data.steps.step_11_normalizer_output.root_files.find(
      file => file.filename === "updated_spec_value_counts_cumulative.csv"
    );
  }

  // 2️⃣ If not found, try fallback in normalization.final_stats
  if (
    !targetFile &&
    data.normalization &&
    data.normalization.final_stats
  ) {
    targetFile = data.normalization.final_stats.find(
      file => file.filename === "final_spec_value_counts_cumulative.csv"
    );
  }

  // 3️⃣ Return result
  if (targetFile) {
    item.json = {
      target_url: targetFile.url,
      filename: targetFile.filename
    };
  } else {
    item.json = {
      error: "Neither updated_spec_value_counts_cumulative.csv nor final_spec_value_counts_cumulative.csv found"
    };
  }
}

return $input.all();

const category = $node["Pre LLM"].json.category;
const mcatid = $node["Merged Data"].json.mcat_id;

const specs = $json.new_specs_missing_on_platform || [];

const now = new Date().toISOString();  // single timestamp for consistency

const rows = specs.map(spec => ({
  mcat_id: mcatid,
  category: category,
  spec_name: spec.spec_name,
  expected_tier: spec.expected_tier,
  total_product_count: spec.total_product_count,
  example_values: (spec.example_values || []).join(", "),
  created_at: now,
}));

return rows.map(r => ({ json: r }));

const grouped = {};

for (const item of items) {
  const row = item.json;
  const spec = row.normalised_spec_name;

  if (!grouped[spec]) {
    grouped[spec] = {
      spec_name: spec,
      total_product_count: 0,
      option_map: {}
    };
  }

  const count = Number(row.prod_count || 0);
  grouped[spec].total_product_count += count;

  // Combine value + unit
  let value = row.normalised_spec_value || "";
  if (row.normalised_spec_value_unit) {
    value = `${value} ${row.normalised_spec_value_unit}`;
  }
  value = value.trim();
  if (!value) continue;

  grouped[spec].option_map[value] =
    (grouped[spec].option_map[value] || 0) + count;
}

const buyer_specs = Object.values(grouped).map(spec => {
  const sortedOptions = Object.entries(spec.option_map)
    .sort((a, b) => b[1] - a[1]);

  const totalCount = spec.total_product_count || 0;
  let runningSum = 0;
  let selected = [];

  // STEP 1 → Select based only on 90% coverage
  for (const [value, count] of sortedOptions) {
    selected.push({ value, count });
    runningSum += count;

    if (totalCount > 0 && runningSum / totalCount >= 0.9) {
      break;
    }
  }

  // STEP 2 → Remove options with count <= 2 AFTER selection
  selected = selected
    .filter(opt => opt.count > 2)
    .map(opt => opt.value);

  return {
    spec_name: spec.spec_name,
    total_product_count: spec.total_product_count,
    example_values: selected
  };
});

return [{ json: { buyer_specs } }];

